#include <DHT.h>
#include <DHT_U.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoJson.h>

// DHT22 Sensor Configuration
#define DHTPIN {{.dhtPin}}
#define DHTTYPE DHT22
DHT dht(DHTPIN, DHTTYPE);

// WiFi Configuration (to be configured per device)
const char* ssid = "YOUR_WIFI_SSID";
const char* password = "YOUR_WIFI_PASSWORD";

// MQTT Configuration
const char* mqtt_server = "{{.mqttServer}}";
const int mqtt_port = {{.mqttPort}};
const char* device_id = "{{.deviceId}}";
const char* location = "{{.location}}";
const unsigned long reading_interval = {{.interval}};

// MQTT Topics
char temp_topic[100];
char humidity_topic[100];
char status_topic[100];
char json_topic[100];

// Global variables
WiFiClient wifiClient;
PubSubClient mqttClient(wifiClient);
unsigned long last_reading_time = 0;
float last_temperature = 0.0;
float last_humidity = 0.0;
bool sensor_error = false;

// Function prototypes
void setup_wifi();
void mqtt_callback(char* topic, byte* payload, unsigned int length);
void publish_sensor_data();
void publish_status();
bool reconnect_mqtt();

void setup() {
  Serial.begin(115200);
  Serial.println("DHT22 MQTT Sensor Starting...");

  // Initialize DHT sensor
  dht.begin();

  // Setup MQTT topics
  snprintf(temp_topic, sizeof(temp_topic), "athena/sensors/%s/%s/temperature", device_id, location);
  snprintf(humidity_topic, sizeof(humidity_topic), "athena/sensors/%s/%s/humidity", device_id, location);
  snprintf(status_topic, sizeof(status_topic), "athena/sensors/%s/%s/status", device_id, location);
  snprintf(json_topic, sizeof(json_topic), "athena/sensors/%s/%s/data", device_id, location);

  // Connect to WiFi
  setup_wifi();

  // Setup MQTT
  mqttClient.setServer(mqtt_server, mqtt_port);
  mqttClient.setCallback(mqtt_callback);

  // Take initial reading
  delay(2000); // Wait for sensor to stabilize
  publish_sensor_data();

  Serial.println("Setup completed!");
}

void loop() {
  // Check WiFi connection
  if (WiFi.status() != WL_CONNECTED) {
    setup_wifi();
  }

  // Check MQTT connection
  if (!mqttClient.connected()) {
    reconnect_mqtt();
  }
  mqttClient.loop();

  // Publish sensor data at specified interval
  unsigned long current_time = millis();
  if (current_time - last_reading_time >= reading_interval) {
    publish_sensor_data();
    last_reading_time = current_time;
  }

  // Small delay to prevent watchdog issues
  delay(100);
}

void setup_wifi() {
  Serial.println("Connecting to WiFi...");

  WiFi.begin(ssid, password);

  int attempts = 0;
  while (WiFi.status() != WL_CONNECTED && attempts < 20) {
    delay(500);
    Serial.print(".");
    attempts++;
  }

  if (WiFi.status() == WL_CONNECTED) {
    Serial.println("");
    Serial.println("WiFi connected!");
    Serial.print("IP address: ");
    Serial.println(WiFi.localIP());
  } else {
    Serial.println("Failed to connect to WiFi");
  }
}

void mqtt_callback(char* topic, byte* payload, unsigned int length) {
  // Handle incoming MQTT messages if needed
  String message = "";
  for (int i = 0; i < length; i++) {
    message += (char)payload[i];
  }

  Serial.print("Message received [" + String(topic) + "]: ");
  Serial.println(message);
}

void publish_sensor_data() {
  // Read temperature and humidity
  float humidity = dht.readHumidity();
  float temperature = dht.readTemperature();

  // Check if readings are valid
  if (isnan(humidity) || isnan(temperature)) {
    Serial.println("Failed to read from DHT sensor!");
    sensor_error = true;
    publish_status();
    return;
  }

  sensor_error = false;
  last_temperature = temperature;
  last_humidity = humidity;

  // Create JSON document
  StaticJsonDocument<200> doc;
  doc["device_id"] = device_id;
  doc["location"] = location;
  doc["timestamp"] = millis();
  doc["temperature"] = temperature;
  doc["humidity"] = humidity;
  doc["unit_temp"] = "°C";
  doc["unit_humidity"] = "%";

  // Publish individual values
  char temp_str[10];
  char humidity_str[10];
  dtostrf(temperature, 4, 2, temp_str);
  dtostrf(humidity, 4, 2, humidity_str);

  mqttClient.publish(temp_topic, temp_str);
  mqttClient.publish(humidity_topic, humidity_str);

  // Publish JSON data
  String json_string;
  serializeJson(doc, json_string);
  mqttClient.publish(json_topic, json_string.c_str());

  // Log to serial
  Serial.print("Temperature: ");
  Serial.print(temperature);
  Serial.print("°C, Humidity: ");
  Serial.print(humidity);
  Serial.println("%");
}

void publish_status() {
  StaticJsonDocument<100> doc;
  doc["device_id"] = device_id;
  doc["location"] = location;
  doc["status"] = sensor_error ? "error" : "online";
  doc["wifi_connected"] = WiFi.status() == WL_CONNECTED;
  doc["timestamp"] = millis();

  String status_string;
  serializeJson(doc, status_string);
  mqttClient.publish(status_topic, status_string.c_str());
}

bool reconnect_mqtt() {
  int attempts = 0;
  while (!mqttClient.connected() && attempts < 3) {
    Serial.print("Attempting MQTT connection...");

    String client_id = "athena-device-" + String(device_id);
    if (mqttClient.connect(client_id.c_str())) {
      Serial.println("connected");

      // Publish initial status
      publish_status();

      return true;
    } else {
      Serial.print("failed, rc=");
      Serial.print(mqttClient.state());
      Serial.println(" try again in 5 seconds");
      delay(5000);
      attempts++;
    }
  }

  return false;
}
